import React, { useEffect, useCallback } from 'react';
import { Linking, Alert, Platform } from 'react-native';
import { useNavigation } from '@react-navigation/native';

const ALLOWED_SCHEMES = ['myapp'];
const ALLOWED_HOSTS = ['profile', 'payment', 'settings', 'home'];

const MAX_PARAM_LENGTH = 1000;
const MAX_PATH_SEGMENTS = 10;

const sanitizeInput = (input) => {
  if (!input || typeof input !== 'string') return '';
  return input.trim().substring(0, MAX_PARAM_LENGTH);
};

const validateUrl = (url) => {
  if (!url || typeof url !== 'string') {
    return { valid: false, error: 'Invalid URL format' };
  }

  try {
    const parsedUrl = new URL(url);
    
    if (!ALLOWED_SCHEMES.includes(parsedUrl.protocol.replace(':', ''))) {
      return { valid: false, error: 'Invalid URL scheme' };
    }

    const host = parsedUrl.hostname || parsedUrl.pathname.split('/')[0];
    if (!ALLOWED_HOSTS.includes(host)) {
      return { valid: false, error: 'Invalid URL host' };
    }

    const pathSegments = parsedUrl.pathname.split('/').filter(Boolean);
    if (pathSegments.length > MAX_PATH_SEGMENTS) {
      return { valid: false, error: 'URL path too long' };
    }

    return { valid: true };
  } catch (error) {
    return { valid: false, error: 'Malformed URL' };
  }
};

const parseDeepLink = (url) => {
  try {
    const parsedUrl = new URL(url);
    const host = parsedUrl.hostname || parsedUrl.pathname.split('/')[0];
    const pathParts = parsedUrl.pathname.split('/').filter(Boolean);
    
    const params = {};
    parsedUrl.searchParams.forEach((value, key) => {
      params[sanitizeInput(key)] = sanitizeInput(value);
    });

    return {
      host: sanitizeInput(host),
      path: pathParts.map(sanitizeInput),
      params,
      fullPath: parsedUrl.pathname
    };
  } catch (error) {
    console.error('Error parsing deep link:', error);
    return null;
  }
};

const validateProfileId = (id) => {
  if (!id) return false;
  const numericId = parseInt(id, 10);
  return !isNaN(numericId) && numericId > 0 && numericId < Number.MAX_SAFE_INTEGER;
};

const validatePaymentAction = (action) => {
  const allowedActions = ['confirm', 'cancel', 'status'];
  return allowedActions.includes(action);
};

const handleProfileRoute = (navigation, path, params) => {
  if (path.length < 2) {
    Alert.alert('Error', 'Invalid profile URL');
    return false;
  }

  const profileId = path[1];
  
  if (!validateProfileId(profileId)) {
    Alert.alert('Error', 'Invalid profile ID');
    return false;
  }

  navigation.navigate('Profile', {
    userId: sanitizeInput(profileId),
    ...params
  });
  
  return true;
};

const handlePaymentRoute = (navigation, path, params) => {
  if (path.length < 2) {
    Alert.alert('Error', 'Invalid payment URL');
    return false;
  }

  const action = path[1];
  
  if (!validatePaymentAction(action)) {
    Alert.alert('Error', 'Invalid payment action');
    return false;
  }

  const routeParams = { action: sanitizeInput(action) };

  if (action === 'confirm' || action === 'status') {
    if (params.transactionId) {
      routeParams.transactionId = sanitizeInput(params.transactionId);
    }
    if (params.amount) {
      const amount = parseFloat(params.amount);
      if (!isNaN(amount) && amount >= 0) {
        routeParams.amount = amount;
      }
    }
  }

  navigation.navigate('Payment', routeParams);
  
  return true;
};

const handleSettingsRoute = (navigation, path, params) => {
  const section = path.length > 1 ? sanitizeInput(path[1]) : 'general';
  const allowedSections = ['general', 'privacy', 'notifications', 'account'];
  
  if (!allowedSections.includes(section)) {
    Alert.alert('Error', 'Invalid settings section');
    return false;
  }

  navigation.navigate('Settings', {
    section,
    ...params
  });
  
  return true;
};

const handleHomeRoute = (navigation, path, params) => {
  navigation.navigate('Home', params);
  return true;
};

const routeHandlers = {
  profile: handleProfileRoute,
  payment: handlePaymentRoute,
  settings: handleSettingsRoute,
  home: handleHomeRoute
};

export const useDeepLinkHandler = () => {
  const navigation = useNavigation();

  const handleDeepLink = useCallback((url) => {
    if (!url) return;

    const validation = validateUrl(url);
    if (!validation.valid) {
      console.error('Invalid deep link:', validation.error);
      Alert.alert('Error', 'Invalid link format');
      return;
    }

    const parsed = parseDeepLink(url);
    if (!parsed) {
      Alert.alert('Error', 'Unable to process link');
      return;
    }

    const { host, path, params } = parsed;
    const handler = routeHandlers[host];

    if (!handler) {
      Alert.alert('Error', 'Unknown link destination');
      return;
    }

    try {
      const success = handler(navigation, path, params);
      if (!success) {
        console.error('Failed to handle route:', host);
      }
    } catch (error) {
      console.error('Error handling deep link:', error);
      Alert.alert('Error', 'Unable to open link');
    }
  }, [navigation]);

  useEffect(() => {
    const handleInitialUrl = async () => {
      try {
        const initialUrl = await Linking.getInitialURL();
        if (initialUrl) {
          handleDeepLink(initialUrl);
        }
      } catch (error) {
        console.error('Error getting initial URL:', error);
      }
    };

    handleInitialUrl();

    const subscription = Linking.addEventListener('url', ({ url }) => {
      handleDeepLink(url);
    });

    return () => {
      subscription.remove();
    };
  }, [handleDeepLink]);

  return { handleDeepLink };
};

export const DeepLinkHandler = ({ children }) => {
  useDeepLinkHandler();
  return children;
};

export const createDeepLink = (route, params = {}) => {
  if (!route || !ALLOWED_HOSTS.includes(route)) {
    throw new Error('Invalid route');
  }

  const sanitizedParams = {};
  Object.keys(params).forEach(key => {
    const sanitizedKey = sanitizeInput(key);
    const sanitizedValue = sanitizeInput(String(params[key]));
    if (sanitizedKey && sanitizedValue) {
      sanitizedParams[sanitizedKey] = sanitizedValue;
    }
  });

  const queryString = new URLSearchParams(sanitizedParams).toString();
  const baseUrl = `myapp://${route}`;
  
  return queryString ? `${baseUrl}?${queryString}` : baseUrl;
};

export const openDeepLink = async (url) => {
  const validation = validateUrl(url);
  if (!validation.valid) {
    throw new Error(validation.error);
  }

  try {
    const supported = await Linking.canOpenURL(url);
    if (supported) {
      await Linking.openURL(url);
      return true;
    } else {
      throw new Error('URL scheme not supported');
    }
  } catch (error) {
    console.error('Error opening deep link:', error);
    throw error;
  }
};

export default useDeepLinkHandler;